const raw = $input.first().json;

if (raw.input) {
  const parsed = typeof raw.input === 'string' ? JSON.parse(raw.input) : raw.input;
  return [{ json: parsed }];
}

return [{ json: raw }];

const items = $input.all();
// console.log('items:', items.length);

function clean(val) {
  if (val === null || val === undefined) return '';
  return String(val).trim();
}

return items.map(item => {
  const row = item.json;

  return {
    json: {
      id_followup:             clean(row.id_followup) || `${Date.now()}-${Math.floor(Math.random()*1000)}`,
      parceiro:                clean(row.parceiro),
      ponto_focal:             clean(row.ponto_focal),
      produto:                 clean(row.produto),
      status:                  clean(row.status),
      status_norm:             clean(row.status).toLowerCase(),
      status_followup:         clean(row.status_followup),
      status_followup_norm:    clean(row.status_followup).toLowerCase(),
      data_inicio_status:      row.data_inicio_status ? String(row.data_inicio_status).trim() : null,
      data_followup_realizado: row.data_followup_realizado ? String(row.data_followup_realizado).trim() : null,
      ultima_cadencia_feita:   clean(row.ultima_cadencia_feita),
      resumo_negociacao:       clean(row.resumo_negociacao),
      observacoes_gerais:      clean(row.observacoes_gerais)
    }
  };
});
